INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('lengua', 'bachillerato', '{1}', 'Los morfemas flexivos indican género número tiempo y persona sin alterar el significado léxico de la palabra'),
('lengua', 'bachillerato', '{1}', 'La derivación consiste en añadir prefijos o sufijos a un lexema para crear nuevas palabras con significado diferente'),
('lengua', 'bachillerato', '{1}', 'Las palabras parasintéticas se forman combinando simultáneamente prefijación y sufijación sobre una base léxica común'),
('lengua', 'bachillerato', '{1}', 'El sintagma verbal funciona como predicado de la oración y tiene como núcleo un verbo en forma personal'),
('lengua', 'bachillerato', '{1}', 'Las oraciones coordinadas copulativas unen elementos que suman información mediante nexos como y e ni'),
('lengua', 'bachillerato', '{1}', 'Las oraciones subordinadas adjetivas funcionan como un adjetivo y van introducidas por un pronombre relativo que las conecta'),
('lengua', 'bachillerato', '{1}', 'El complemento indirecto designa al destinatario de la acción verbal y puede sustituirse por los pronombres le o les'),
('lengua', 'bachillerato', '{1}', 'El complemento circunstancial expresa las circunstancias de lugar tiempo modo o causa en que se realiza la acción'),
('lengua', 'bachillerato', '{1}', 'Las oraciones impersonales carecen de sujeto gramatical y se construyen con verbos meteorológicos o con el pronombre se'),
('lengua', 'bachillerato', '{1}', 'La oración pasiva traslada el complemento directo a la posición de sujeto paciente que recibe la acción del verbo'),
('lengua', 'bachillerato', '{1}', 'El Cantar de Mio Cid es la obra más importante del mester de juglaría y narra las hazañas de Rodrigo Díaz'),
('lengua', 'bachillerato', '{1}', 'El mester de clerecía empleaba la cuaderna vía un tipo de estrofa con versos alejandrinos y rima consonante'),
('lengua', 'bachillerato', '{1}', 'Gonzalo de Berceo fue el primer poeta castellano de nombre conocido y escribió los Milagros de Nuestra Señora'),
('lengua', 'bachillerato', '{1}', 'El Libro de Buen Amor del Arcipreste de Hita combina elementos didácticos y humorísticos con temas amorosos variados'),
('lengua', 'bachillerato', '{1}', 'Don Juan Manuel elevó la prosa castellana medieval con El conde Lucanor una colección de cuentos ejemplares moralizantes'),
('lengua', 'bachillerato', '{1}', 'Las jarchas mozárabes son los primeros testimonios líricos escritos en lengua romance de la Península Ibérica'),
('lengua', 'bachillerato', '{1}', 'La Celestina de Fernando de Rojas marca la transición entre la literatura medieval y la renacentista con su realismo'),
('lengua', 'bachillerato', '{1}', 'Jorge Manrique compuso las Coplas a la muerte de su padre una elegía que reflexiona sobre la fugacidad de la vida'),
('lengua', 'bachillerato', '{1}', 'El romancero viejo recoge composiciones de transmisión oral que narran episodios épicos históricos y legendarios del medievo'),
('lengua', 'bachillerato', '{1}', 'El Lazarillo de Tormes inauguró la novela picaresca con su estructura autobiográfica y su visión crítica de la sociedad'),
('lengua', 'bachillerato', '{1}', 'La poesía mística de Santa Teresa describe las experiencias del alma en su camino de perfección espiritual interior'),
('lengua', 'bachillerato', '{1}', 'El soneto consta de catorce versos endecasílabos distribuidos en dos cuartetos y dos tercetos con rima consonante'),
('lengua', 'bachillerato', '{1}', 'La lira es una estrofa de cinco versos que alterna heptasílabos y endecasílabos utilizada por Garcilaso y Fray Luis'),
('lengua', 'bachillerato', '{1}', 'Calderón de la Barca escribió dramas filosóficos como La vida es sueño que reflexionan sobre la libertad y el destino'),
('lengua', 'bachillerato', '{1}', 'El auto sacramental es una pieza teatral alegórica de tema eucarístico que Calderón llevó a su máxima perfección'),
('lengua', 'bachillerato', '{1}', 'Tirso de Molina creó el personaje de Don Juan en El burlador de Sevilla un mito literario universal'),
('lengua', 'bachillerato', '{1}', 'El teatro del Siglo de Oro español se representaba en corrales de comedias espacios abiertos con público de todas clases'),
('lengua', 'bachillerato', '{1}', 'La antítesis es una figura retórica que contrapone dos ideas o expresiones de significado opuesto para crear contraste'),
('lengua', 'bachillerato', '{1}', 'La hipérbole consiste en exagerar de forma desmesurada una cualidad o circunstancia con finalidad expresiva o cómica'),
('lengua', 'bachillerato', '{1}', 'La sinestesia atribuye una cualidad sensorial a un sentido diferente como en el verso de la dulce melodía azul'),
('lengua', 'bachillerato', '{1}', 'El hipérbaton altera el orden lógico de las palabras en la oración para lograr un efecto estético o enfático'),
('lengua', 'bachillerato', '{1}', 'La anáfora repite una o varias palabras al comienzo de versos o frases sucesivas para intensificar el mensaje'),
('lengua', 'bachillerato', '{1}', 'La metonimia sustituye un término por otro con el que mantiene una relación de contigüidad lógica o causal'),
('lengua', 'bachillerato', '{1}', 'El comentario de texto debe comenzar por situar la obra en su contexto histórico literario y cultural correspondiente'),
('lengua', 'bachillerato', '{1}', 'La estructura interna de un texto analiza cómo se organizan las ideas en introducción desarrollo y conclusión'),
('lengua', 'bachillerato', '{1}', 'Los textos expositivos presentan información de forma objetiva y ordenada utilizando un registro formal y preciso'),
('lengua', 'bachillerato', '{1}', 'El registro lingüístico varía según la situación comunicativa pudiendo ser formal coloquial técnico o literario'),
('lengua', 'bachillerato', '{1}', 'Las funciones del lenguaje según Jakobson son la referencial emotiva conativa fática metalingüística y poética'),
('lengua', 'bachillerato', '{1}', 'La función poética del lenguaje centra la atención en la forma del mensaje mediante recursos estilísticos y rítmicos'),
('lengua', 'bachillerato', '{1}', 'El verso endecasílabo de once sílabas fue el metro fundamental de la poesía culta española desde el Renacimiento'),
('lengua', 'bachillerato', '{1}', 'La rima consonante repite todos los sonidos desde la última vocal acentuada mientras la asonante solo repite las vocales'),
('lengua', 'bachillerato', '{1}', 'Las Églogas de Garcilaso recrean un paisaje idealizado donde pastores cultos dialogan sobre el amor y la naturaleza'),
('lengua', 'bachillerato', '{1}', 'La Oda a la vida retirada de Fray Luis expresa el deseo de huir del mundo para alcanzar la paz interior'),
('lengua', 'bachillerato', '{1}', 'El Cántico espiritual de San Juan de la Cruz simboliza la búsqueda del alma enamorada que persigue al Amado divino'),
('lengua', 'bachillerato', '{1}', 'Góngora compuso las Soledades un poema extenso de lenguaje oscuro cargado de cultismos y referencias mitológicas'),
('lengua', 'bachillerato', '{1}', 'El Buscón de Quevedo narra la vida de un pícaro con un estilo mordaz lleno de juegos de palabras e ingenio'),
('lengua', 'bachillerato', '{1}', 'La comedia de capa y espada presenta enredos amorosos entre galanes y damas con criados graciosos como contrapunto'),
('lengua', 'bachillerato', '{1}', 'Las novelas ejemplares de Cervantes ofrecen doce relatos breves que exploran diversos tipos humanos y conflictos sociales'),
('lengua', 'bachillerato', '{1}', 'La segunda parte del Quijote profundiza en la psicología del personaje que es consciente de su propia fama literaria'),
('lengua', 'bachillerato', '{1}', 'El atributo es un complemento que acompaña a verbos copulativos como ser estar y parecer y predica del sujeto'),
('lengua', 'bachillerato', '{1}', 'El complemento predicativo predica simultáneamente del sujeto o del complemento directo con un verbo no copulativo'),
('lengua', 'bachillerato', '{1}', 'Las oraciones subordinadas adverbiales expresan relaciones de causa consecuencia condición finalidad o concesión'),
('lengua', 'bachillerato', '{1}', 'El leísmo consiste en usar el pronombre le como complemento directo masculino singular y es aceptado por la norma'),
('lengua', 'bachillerato', '{1}', 'El dequeísmo es un error que consiste en anteponer la preposición de ante la conjunción que sin justificación sintáctica'),
('lengua', 'bachillerato', '{1}', 'Los marcadores discursivos organizan el texto señalando relaciones lógicas como adición contraste o conclusión entre ideas'),
('lengua', 'bachillerato', '{1}', 'La perífrasis verbal es la combinación de un verbo auxiliar y una forma no personal que expresa matices aspectuales o modales'),
('lengua', 'bachillerato', '{1}', 'El modo subjuntivo expresa deseo duda probabilidad o mandato frente al indicativo que presenta hechos como reales'),
('lengua', 'bachillerato', '{1}', 'La composición forma palabras nuevas uniendo dos o más lexemas como en sacapuntas guardabosques o mediodía'),
('lengua', 'bachillerato', '{1}', 'Los neologismos son palabras nuevas que surgen para designar realidades recientes como ciberacoso o videollamada'),
('lengua', 'bachillerato', '{1}', 'Los préstamos lingüísticos son palabras adoptadas de otras lenguas que se adaptan a la fonética y morfología del español'),
('lengua', 'bachillerato', '{1}', 'La lírica cancioneril del siglo XV utilizaba un lenguaje cortesano y conceptista para expresar el amor idealizado'),
('lengua', 'bachillerato', '{1}', 'La Danza de la Muerte es un género medieval que recuerda la igualdad de todos los estamentos ante la muerte'),
('lengua', 'bachillerato', '{1}', 'Fernando de Herrera representó la escuela sevillana del Renacimiento con una poesía de tono elevado y patriótico'),
('lengua', 'bachillerato', '{1}', 'El tópico literario del carpe diem invita a disfrutar de la juventud y la belleza antes de que el tiempo las destruya'),
('lengua', 'bachillerato', '{1}', 'El tópico del beatus ille elogia la vida sencilla del campo frente a las ambiciones y ruido de la ciudad'),
('lengua', 'bachillerato', '{1}', 'El locus amoenus describe un paisaje natural idealizado con fuentes árboles y brisa que sirve de marco a la poesía'),
('lengua', 'bachillerato', '{1}', 'La alegoría es una figura que expresa un significado oculto a través de una sucesión de metáforas relacionadas'),
('lengua', 'bachillerato', '{1}', 'El asíndeton suprime los nexos entre elementos de una enumeración para dar rapidez y dinamismo a la expresión'),
('lengua', 'bachillerato', '{1}', 'El polisíndeton repite conjunciones innecesarias para ralentizar el ritmo y dar solemnidad o intensidad al discurso'),
('lengua', 'bachillerato', '{1}', 'Las variedades diatópicas del español se manifiestan en diferencias fonéticas léxicas y gramaticales entre regiones'),
('lengua', 'bachillerato', '{1}', 'El seseo consiste en pronunciar la z y la c ante e i como una s fricativa alveolar sorda y es típico de Hispanoamérica'),
('lengua', 'bachillerato', '{1}', 'La coherencia de un texto depende de que sus ideas progresen de forma lógica sin contradicciones ni saltos temáticos'),
('lengua', 'bachillerato', '{1}', 'La cohesión textual se logra mediante mecanismos como la referencia la sustitución la elipsis y la conexión entre oraciones'),
('lengua', 'bachillerato', '{1}', 'El texto narrativo relata hechos reales o ficticios organizados en una secuencia temporal con un narrador que los presenta'),
('lengua', 'bachillerato', '{1}', 'El narrador omnisciente conoce los pensamientos y sentimientos de todos los personajes y puede anticipar acontecimientos futuros'),
('lengua', 'bachillerato', '{1}', 'Los actos de habla según Austin y Searle clasifican los enunciados según lo que hacen al ser pronunciados'),
('lengua', 'bachillerato', '{1}', 'La deixis es un mecanismo lingüístico que señala elementos del contexto comunicativo como el lugar el tiempo o la persona'),
('lengua', 'bachillerato', '{1}', 'El complemento de régimen verbal es un sintagma preposicional exigido por el verbo que completa su significado'),
('lengua', 'bachillerato', '{1}', 'Las proposiciones yuxtapuestas se relacionan entre sí sin nexos explícitos separadas únicamente por signos de puntuación'),
('lengua', 'bachillerato', '{1}', 'El Marqués de Santillana introdujo el soneto italianizante en la poesía castellana del siglo quince anticipando el Renacimiento'),
('lengua', 'bachillerato', '{1}', 'La silva es una composición que combina libremente versos endecasílabos y heptasílabos con rima consonante variable'),
('lengua', 'bachillerato', '{1}', 'La novela pastoril idealiza la vida rural y presenta pastores cultos que expresan sus cuitas amorosas en un marco bucólico'),
('lengua', 'bachillerato', '{1}', 'La novela bizantina narra peripecias de amantes separados que superan múltiples aventuras hasta reencontrarse al final'),
('lengua', 'bachillerato', '{1}', 'La novela morisca presenta las relaciones entre moros y cristianos con un tono idealizado de cortesía y nobleza caballeresca'),
('lengua', 'bachillerato', '{1}', 'Cervantes parodia los libros de caballerías en el Quijote mostrando el choque entre los ideales del caballero y la realidad');
INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('lengua', 'bachillerato', '{2}', 'La Ilustración española promovió la razón la educación y el progreso frente a la superstición y las tradiciones arcaicas'),
