INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('historia-mundo', 'bachillerato', '{1}', 'La Declaración de los Derechos del Hombre y del Ciudadano de 1789 proclamó la libertad la igualdad y la soberanía nacional'),
('historia-mundo', 'bachillerato', '{1}', 'La toma de la Bastilla el 14 de julio de 1789 se convirtió en el símbolo de la Revolución Francesa'),
('historia-mundo', 'bachillerato', '{1}', 'El Terror jacobino de Robespierre llevó a miles de personas a la guillotina en nombre de la virtud republicana'),
('historia-mundo', 'bachillerato', '{1}', 'Napoleón Bonaparte extendió los principios revolucionarios por Europa mediante conquistas militares y reformas administrativas'),
('historia-mundo', 'bachillerato', '{1}', 'El Congreso de Viena de 1815 restauró el mapa europeo anterior a Napoleón basándose en el principio de legitimidad monárquica'),
('historia-mundo', 'bachillerato', '{1}', 'Las revoluciones liberales de 1820 1830 y 1848 sacudieron Europa reclamando constituciones y derechos civiles para los ciudadanos'),
('historia-mundo', 'bachillerato', '{1}', 'La unificación italiana se completó en 1870 bajo el liderazgo de Cavour Garibaldi y el rey Víctor Manuel Segundo'),
('historia-mundo', 'bachillerato', '{1}', 'Bismarck unificó Alemania mediante tres guerras victoriosas y proclamó el Imperio alemán en Versalles en 1871'),
('historia-mundo', 'bachillerato', '{1}', 'La máquina de vapor de Watt fue el motor de la primera revolución industrial que transformó la producción textil y minera'),
('historia-mundo', 'bachillerato', '{1}', 'El ferrocarril revolucionó el transporte en el siglo diecinueve conectando ciudades y mercados a una velocidad sin precedentes'),
('historia-mundo', 'bachillerato', '{1}', 'El movimiento obrero surgió como respuesta a las duras condiciones de trabajo en las fábricas de la revolución industrial'),
('historia-mundo', 'bachillerato', '{1}', 'El ludismo fue un movimiento de protesta obrera que destruía máquinas considerándolas responsables del desempleo y la miseria'),
('historia-mundo', 'bachillerato', '{1}', 'El cartismo británico reclamó el sufragio universal masculino y mejores condiciones laborales mediante peticiones al Parlamento'),
('historia-mundo', 'bachillerato', '{1}', 'Karl Marx y Friedrich Engels publicaron el Manifiesto Comunista en 1848 llamando a la unión de los trabajadores del mundo'),
('historia-mundo', 'bachillerato', '{1}', 'La Primera Internacional reunió a socialistas anarquistas y sindicalistas para coordinar la lucha obrera a escala mundial'),
('historia-mundo', 'bachillerato', '{1}', 'El anarquismo de Bakunin defendía la abolición del Estado y la organización libre de los trabajadores sin autoridad central'),
('historia-mundo', 'bachillerato', '{1}', 'La Conferencia de Berlín de 1884 estableció las reglas para el reparto colonial de África entre las potencias europeas'),
('historia-mundo', 'bachillerato', '{1}', 'El colonialismo justificó la dominación europea mediante la supuesta misión civilizadora sobre los pueblos considerados inferiores'),
('historia-mundo', 'bachillerato', '{1}', 'La rivalidad colonial entre potencias europeas fue una de las causas principales del estallido de la Primera Guerra Mundial'),
('historia-mundo', 'bachillerato', '{1}', 'La guerra de trincheras convirtió el frente occidental de la Primera Guerra Mundial en un sangriento estancamiento durante años'),
('historia-mundo', 'bachillerato', '{1}', 'La entrada de Estados Unidos en la guerra en 1917 inclinó la balanza a favor de los aliados contra las Potencias Centrales'),
('historia-mundo', 'bachillerato', '{1}', 'La Sociedad de Naciones fue creada tras la Primera Guerra Mundial para mantener la paz pero careció de medios efectivos'),
('historia-mundo', 'bachillerato', '{1}', 'La revolución bolchevique de octubre de 1917 instauró un gobierno comunista liderado por Lenin en la antigua Rusia zarista'),
('historia-mundo', 'bachillerato', '{1}', 'Lenin aplicó el marxismo adaptándolo a las condiciones rusas con un partido de vanguardia que dirigiría la revolución proletaria'),
